import{_ as t,o,c as r,a0 as a}from"./chunks/framework.DTwdCQre.js";const m=JSON.parse('{"title":"Runtime Package Map","description":"Package-level map for contributors working on claude-code-Go runtime behavior.","frontmatter":{"title":"Runtime Package Map","description":"Package-level map for contributors working on claude-code-Go runtime behavior."},"headers":[],"relativePath":"architecture/runtime-package-map.md","filePath":"architecture/runtime-package-map.md","lastUpdated":1777713767000}'),d={name:"architecture/runtime-package-map.md"};function n(i,e,s,c,l,p){return o(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="runtime-package-map" tabindex="-1">Runtime Package Map <a class="header-anchor" href="#runtime-package-map" aria-label="Permalink to &quot;Runtime Package Map&quot;">​</a></h1><p>This page maps product workflows to the Go packages that own them. Use it before changing runtime behavior so fixes land in the correct layer.</p><h2 id="runtime-flow" tabindex="-1">Runtime Flow <a class="header-anchor" href="#runtime-flow" aria-label="Permalink to &quot;Runtime Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmd/go-code  (entrypoint, setup, doctor, replay)</span></span>
<span class="line"><span>  -&gt; config loader          (internal/config)</span></span>
<span class="line"><span>  -&gt; provider resolution    (internal/provider/registry)</span></span>
<span class="line"><span>  -&gt; provider adapter       (internal/provider/anthropic | internal/provider/openai)</span></span>
<span class="line"><span>  -&gt; tool registry          (internal/tool, internal/tool/init)</span></span>
<span class="line"><span>  -&gt; MCP tools              (internal/tool/mcp)</span></span>
<span class="line"><span>  -&gt; permission policy      (internal/permission)</span></span>
<span class="line"><span>  -&gt; agent loop             (internal/agent)</span></span>
<span class="line"><span>  -&gt; TUI or REPL            (pkg/tui | pkg/tty, internal/command)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="package-ownership" tabindex="-1">Package Ownership <a class="header-anchor" href="#package-ownership" aria-label="Permalink to &quot;Package Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Responsibility</th><th>Notes</th></tr></thead><tbody><tr><td><code>cmd/go-code</code></td><td>Process entrypoint, flags, subcommands (doctor, replay, setup), runtime wiring.</td><td>Keep orchestration here; subcommands live in the same package but must not import each other.</td></tr><tr><td><code>pkg/tui</code></td><td>Default Bubble Tea interactive TUI.</td><td>Should delegate slash commands to <code>internal/command</code>.</td></tr><tr><td><code>pkg/tty</code></td><td>Legacy line-based REPL.</td><td>Reference for slash command coverage until TUI reaches parity.</td></tr><tr><td><code>internal/agent</code></td><td>Agent loop, history, compaction, recovery, session trace hooks.</td><td>Owns stop-reason dispatch and tool-result feedback.</td></tr><tr><td><code>internal/api</code></td><td>Anthropic request/response types, HTTP client, SSE parsing, API error classification.</td><td>Keep provider-neutral behavior out of this package when possible.</td></tr><tr><td><code>internal/provider</code></td><td>Provider interface definition and normalized error types (<code>ClassifiedError</code>).</td><td>The <code>Provider</code> interface lives here; implementations live in sub-packages.</td></tr><tr><td><code>internal/provider/registry</code></td><td>Provider resolution, model-to-provider detection, base URL defaults.</td><td>Single place for routing <code>&quot;anthropic&quot;</code> vs <code>&quot;openai&quot;</code> provider strings at startup.</td></tr><tr><td><code>internal/provider/anthropic</code></td><td>Anthropic Messages API adapter.</td><td>Implements <code>Provider</code> from <code>internal/provider</code>.</td></tr><tr><td><code>internal/provider/openai</code></td><td>OpenAI Chat Completions API adapter.</td><td>Implements <code>Provider</code> from <code>internal/provider</code>.</td></tr><tr><td><code>internal/config</code></td><td>Configuration loading, defaults, env vars, CLI overrides.</td><td>Load order: defaults &lt; user config &lt; project config &lt; env vars &lt; CLI flags.</td></tr><tr><td><code>internal/tool</code></td><td>Tool interface, registry, and tool definition types.</td><td>Registry dispatches tool calls by name.</td></tr><tr><td><code>internal/tool/init</code></td><td>Registers all builtin tools (Bash, Read, Write, Edit, Glob, Grep, Diff, Tree, WebFetch, TodoWrite, Notebook) into the registry.</td><td>Single point for tool registration.</td></tr><tr><td><code>internal/tool/builtin</code></td><td>Built-in tool implementations.</td><td>Side effects must be permission-gated by the caller. Individual files: <code>bash.go</code>, <code>read.go</code>, <code>write.go</code>, <code>edit.go</code>, <code>glob.go</code>, <code>grep.go</code>, <code>diff.go</code>, <code>tree.go</code>, <code>webfetch.go</code>, <code>todo.go</code>, <code>notebook.go</code>.</td></tr><tr><td><code>internal/tool/mcp</code></td><td>MCP client, transport, and adapter.</td><td>MCP tools enter the same registry and permission flow as builtins.</td></tr><tr><td><code>internal/permission</code></td><td>Permission modes, policy evaluation, rules, prompter, file boundaries, bash semantic checks.</td><td>Evaluation order: deny rules &gt; allow rules &gt; session memory &gt; tool requirement &gt; mode default.</td></tr><tr><td><code>internal/session</code></td><td>JSONL session persistence, list, replay.</td><td>Needs a normalized schema for cross-UI replay.</td></tr><tr><td><code>internal/command</code></td><td>Shared slash command handler (<code>/help</code>, <code>/model</code>, <code>/clear</code>, <code>/sessions</code>, <code>/compact</code>, etc.).</td><td>Both TUI and legacy REPL route through the same handlers.</td></tr><tr><td><code>internal/hooks</code></td><td>Pre/post tool execution hooks.</td><td>Pre-hook failures should block tool execution.</td></tr><tr><td><code>internal/skills</code></td><td>User-defined reusable prompts/workflows: loader, registry, types.</td><td>Invalid skill files must not break startup.</td></tr><tr><td><code>internal/lsp</code></td><td>LSP client features (hover, definition, references, symbols, diagnostics, gate).</td><td>Optional surface; should fail closed when no server is configured.</td></tr><tr><td><code>internal/update</code></td><td>Release checking and binary download.</td><td>User-triggered network behavior only.</td></tr><tr><td><code>internal/cost</code></td><td>Token and cost tracking.</td><td>Provider pricing assumptions must be documented.</td></tr><tr><td><code>internal/telemetry</code></td><td>Optional local telemetry primitives and consent.</td><td>Keep disabled until product/privacy story is explicit.</td></tr><tr><td><code>internal/logger</code></td><td>Structured logging (slog) and trace-level helpers.</td><td>Used across all packages for consistent log output.</td></tr></tbody></table><h2 id="contributor-rules" tabindex="-1">Contributor Rules <a class="header-anchor" href="#contributor-rules" aria-label="Permalink to &quot;Contributor Rules&quot;">​</a></h2><ul><li>UI packages (<code>pkg/tui</code>, <code>pkg/tty</code>) must not duplicate command semantics; use <code>internal/command</code> instead.</li><li>Tool implementations perform local validation, but permission approval belongs above tool execution (in <code>internal/permission</code>).</li><li>Provider adapters normalize errors via <code>ClassifyError</code> / <code>ClassifyHTTPStatus</code> before they reach UI code.</li><li>Tests that require sockets, home-directory writes, or built binaries must document those requirements in their test functions.</li><li>Public docs should only claim workflows that are verified by tests or listed in <code>PARITY.md</code>.</li></ul>`,8)])])}const g=t(d,[["render",n]]);export{m as __pageData,g as default};
